"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import type * as React from "react";
import { cn } from "@/lib/utils";

/**
 * Section: an opinionated settings-page primitive. A bordered card with
 * a structured header (title + subtitle), content area, and a two-column
 * footer (status on the left, actions on the right).
 *
 * Distinct from `Card`, which is a general-purpose surface primitive
 * (mix-and-match boolean props). Section prescribes a specific layout
 * that shows up over and over on settings pages, plan comparisons, and
 * project configuration screens.
 */
export function Section({
  className,
  render,
  ...props
}: useRender.ComponentProps<"section">): React.ReactElement {
  const defaultProps = {
    className: cn(
      // Elevated surface + hairline: matches Card / Menu popup direction.
      // In light mode the card lifts to pure white against off-white
      // canvas; in dark it sits at the palette rung. Softer hairline
      // border keeps the edge crisp without shouting.
      "flex flex-col rounded-[var(--radius-12)] bg-surface-elevated border border-hairline text-ink",
      className,
    ),
    "data-slot": "section",
  };

  return useRender({
    defaultTagName: "section",
    props: mergeProps<"section">(defaultProps, props),
    render,
  });
}

export function SectionHeader({
  className,
  render,
  ...props
}: useRender.ComponentProps<"div">): React.ReactElement {
  const defaultProps = {
    className: cn("flex flex-col gap-1.5 px-6 py-5", className),
    "data-slot": "section-header",
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props),
    render,
  });
}

export function SectionTitle({
  className,
  render,
  ...props
}: useRender.ComponentProps<"h3">): React.ReactElement {
  const defaultProps = {
    className: cn("text-display-20 text-ink", className),
    "data-slot": "section-title",
  };

  return useRender({
    defaultTagName: "h3",
    props: mergeProps<"h3">(defaultProps, props),
    render,
  });
}

export function SectionSubtitle({
  className,
  render,
  ...props
}: useRender.ComponentProps<"p">): React.ReactElement {
  const defaultProps = {
    className: cn("text-body-14 text-ink", className),
    "data-slot": "section-subtitle",
  };

  return useRender({
    defaultTagName: "p",
    props: mergeProps<"p">(defaultProps, props),
    render,
  });
}

/**
 * SectionContent: main body of a Section. Renders below the header,
 * above the footer, with matching padding.
 */
export function SectionContent({
  className,
  render,
  ...props
}: useRender.ComponentProps<"div">): React.ReactElement {
  const defaultProps = {
    className: cn("flex flex-col gap-4 px-6 pb-6", className),
    "data-slot": "section-content",
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props),
    render,
  });
}

export interface SectionFooterProps
  extends useRender.ComponentProps<"footer"> {
  /** Use the tonal secondary surface (`gray-100`) as the footer background. */
  secondary?: boolean;
}

/**
 * SectionFooter: bordered footer with a two-column layout. Place a
 * `SectionFooterStatus` on the left and `SectionFooterActions` on the
 * right. When only one child is present it aligns naturally.
 */
export function SectionFooter({
  className,
  render,
  ...props
}: SectionFooterProps): React.ReactElement {
  const defaultProps = {
    className: cn(
      // Softer top divider; no bg fill (surface-1 was invisible on the
      // elevated card in dark mode). The divider carries the region
      // separation on its own.
      "flex flex-wrap items-center justify-between gap-3 px-6 py-3.5 rounded-b-[calc(var(--radius-12)-1px)]",
      "border-t border-hairline",
      className,
    ),
    "data-slot": "section-footer",
  };

  return useRender({
    defaultTagName: "footer",
    props: mergeProps<"footer">(defaultProps, props),
    render,
  });
}

/** Left-aligned status text inside a SectionFooter. */
export function SectionFooterStatus({
  className,
  render,
  ...props
}: useRender.ComponentProps<"div">): React.ReactElement {
  const defaultProps = {
    className: cn("text-body-14 text-ink", className),
    "data-slot": "section-footer-status",
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props),
    render,
  });
}

/** Right-aligned actions row inside a SectionFooter. */
export function SectionFooterActions({
  className,
  render,
  ...props
}: useRender.ComponentProps<"div">): React.ReactElement {
  const defaultProps = {
    className: cn("flex items-center gap-2", className),
    "data-slot": "section-footer-actions",
  };

  return useRender({
    defaultTagName: "div",
    props: mergeProps<"div">(defaultProps, props),
    render,
  });
}

/* --------------------------- Rows (settings-page pattern) --------------------------- */

export interface SectionRowProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  /** Row heading (bold, ink). */
  title: React.ReactNode;
  /** Secondary line under the title (muted). */
  description?: React.ReactNode;
}

/**
 * SectionRow: one setting inside a Section, following the two-column
 * settings-page pattern:
 *
 *   [ title       control ]
 *   [ description         ]
 *
 * Rows are separated from each other by a hairline top border (except
 * the first). The control area is whatever you pass as children --
 * typically a Select / Switch / Kbd chip.
 *
 * Usage:
 *   <Section>
 *     <SectionRow title="Default home view" description="Which view opens when you launch the app">
 *       <Select value={home} onValueChange={setHome}>...</Select>
 *     </SectionRow>
 *     <SectionRow title="Convert text emoticons" description="Strings like :) become 🙂">
 *       <Switch checked={emoji} onCheckedChange={setEmoji} />
 *     </SectionRow>
 *   </Section>
 */
export function SectionRow({
  title,
  description,
  className,
  children,
  ...props
}: SectionRowProps): React.ReactElement {
  return (
    <div
      data-slot="section-row"
      className={cn(
        // First row inside a Section gets no border-top; every subsequent
        // row picks up the hairline divider via `[&+&]:` -- authored on
        // the parent selector so consumers don't have to remember to skip
        // the first row.
        "flex items-center gap-4 px-6 py-4 [&+&]:border-t [&+&]:border-hairline",
        className,
      )}
      {...props}
    >
      <div className="flex min-w-0 flex-1 flex-col gap-1">
        <div className="text-button-14 text-ink">{title}</div>
        {description != null && (
          <div className="text-body-13 text-ink-muted">{description}</div>
        )}
      </div>
      {children != null && (
        <div
          className="flex shrink-0 items-center gap-2"
          data-slot="section-row-control"
        >
          {children}
        </div>
      )}
    </div>
  );
}
